using namespace std;

int main()
{
    int T;
    cin >> T;
    cout << fixed << setprecision(8);
    while(T --) {
        int n;
        cin >> n;
        int a[n][n];
        int dp[n][n];
        for(int i = 0; i < n; i ++) {
            for(int j = 0; j < n; j ++) {
                cin >> a[i][j];
                dp[i][j] = 0;
                if(i && j) dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
                else if(i) dp[i][j] = dp[i - 1][j];
                else if(j) dp[i][j] = dp[i][j - 1];
                dp[i][j] += a[i][j];   
            }
        }
        if(dp[n - 1][n - 1] < 0) cout << "Bad Judges\n";
        else cout << 1.0 * dp[n - 1][n - 1] / (2 * n - 3) << '\n';
    }
}

